1	<script lang="ts">
2		import type { PageData } from './$types';
3		import { goto, invalidateAll } from '$app/navigation';
4		import { resolve } from '$app/paths';
5		import { page } from '$app/stores';
6		import { tick } from 'svelte';
7		import { marked } from 'marked';
8		import DOMPurify from 'isomorphic-dompurify';
9		import { ArrowLeft, Pencil } from 'lucide-svelte';
10		import { gql } from 'graphql-request';
11		import { createClient } from '$lib/gql/client';
12	
13		let { data }: { data: PageData } = $props();
14	
15		let content = $derived(data.content ?? '');
16		let editing = $state(false);
17		let editContent = $state('');
18		let editorMode = $state<'wysiwyg' | 'plain'>('wysiwyg');
19		let wysiwygDraftBody = $state('');
20		let saving = $state(false);
21		let saveError = $state<string | null>(null);
22		let renderedElement: HTMLDivElement | undefined = $state();
23	
24		// Sanitize: marked dropped its built-in sanitize option, so raw <script>,
25		// onerror handlers, and javascript: URIs in a document would execute in
26		// the admin UI context. A compromised document on disk must not be able
27		// to hijack a session that has documentWrite access.
28		let rendered = $derived(renderMarkdown(splitMarkdown(content).body));
29		let editParts = $derived(splitMarkdown(editContent));
30		let renderedEditBody = $derived(renderMarkdown(editParts.body));
31	
32		const DOCUMENT_WRITE = gql`
33			mutation DocumentWrite($path: String!, $content: String!) {
34				documentWrite(path: $path, content: $content) {
35					path
36					content
37				}
38			}
39		`;
40	
41		interface DocumentWriteResult {
42			documentWrite: { path: string; content?: string | null };
43		}
44	
45		function splitMarkdown(markdown: string) {
46			const match = markdown.match(/^---\r?\n[\s\S]*?\r?\n---(?:\r?\n|$)/);
47			if (!match) {
48				return { frontmatter: '', frontmatterText: '', body: markdown };
49			}
50			const frontmatter = match[0];
51			const frontmatterText = frontmatter.replace(/^---\r?\n/, '').replace(/\r?\n---(?:\r?\n|$)/, '');
52			return {
53				frontmatter,
54				frontmatterText,
55				body: markdown.slice(frontmatter.length)
56			};
57		}
58	
59		function renderMarkdown(markdown: string) {
60			return markdown ? DOMPurify.sanitize(marked.parse(markdown) as string) : '';
61		}
62	
63		function normalizeMarkdownBody(body: string) {
64			return body
65				.replace(/\u00a0/g, ' ')
66				.replace(/\n{3,}/g, '\n\n')
67				.trim();
68		}
69	
70		function htmlFragmentToMarkdown(root: HTMLElement) {
71			const blocks: string[] = [];
72	
73			function textOf(node: Node) {
74				return (node.textContent ?? '').replace(/\u00a0/g, ' ').trim();
75			}
76	
77			function addBlock(value: string) {
78				const normalized = normalizeMarkdownBody(value);
79				if (normalized) blocks.push(normalized);
80			}
81	
82			for (const child of Array.from(root.childNodes)) {
83				if (child.nodeType === Node.TEXT_NODE) {
84					addBlock(child.textContent ?? '');
85					continue;
86				}
87				if (!(child instanceof HTMLElement)) continue;
88				const tag = child.tagName.toLowerCase();
89				if (/^h[1-6]$/.test(tag)) {
90					addBlock(`${'#'.repeat(Number(tag.slice(1)))} ${textOf(child)}`);
91				} else if (tag === 'ul' || tag === 'ol') {
92					const ordered = tag === 'ol';
93					const items = Array.from(child.querySelectorAll(':scope > li')).map((li, index) => {
94						const marker = ordered ? `${index + 1}.` : '-';
95						return `${marker} ${textOf(li)}`;
96					});
97					addBlock(items.join('\n'));
98				} else if (tag === 'pre') {
99					blocks.push(`\`\`\`\n${child.textContent ?? ''}\n\`\`\``);
100				} else if (tag === 'blockquote') {
101					addBlock(
102						textOf(child)
103							.split('\n')
104							.map((line) => `> ${line}`)
105							.join('\n')
106					);
107				} else {
108					addBlock(textOf(child));
109				}
110			}
111	
112			return blocks.join('\n\n');
113		}
114	
115		function commitWysiwygDraft() {
116			if (editorMode !== 'wysiwyg') return;
117			const body = normalizeMarkdownBody(wysiwygDraftBody);
118			editContent = `${editParts.frontmatter}${body}${body ? '\n' : ''}`;
119		}
120	
121		function setEditorMode(mode: 'wysiwyg' | 'plain') {
122			if (mode === editorMode) return;
123			commitWysiwygDraft();
124			editorMode = mode;
125			if (mode === 'wysiwyg') {
126				wysiwygDraftBody = splitMarkdown(editContent).body;
127			}
128		}
129	
130		function handleWysiwygInput(event: Event) {
131			wysiwygDraftBody = htmlFragmentToMarkdown(event.currentTarget as HTMLElement);
132		}
133	
134		function isExternalHttpLink(href: string) {
135			return /^https?:\/\//i.test(href);
136		}
137	
138		function encodeDocPath(path: string) {
139			return path.split('/').map(encodeURIComponent).join('/');
140		}
141	
142		function resolveDocumentHref(href: string) {
143			const baseDir = data.path.includes('/')
144				? data.path.slice(0, data.path.lastIndexOf('/') + 1)
145				: '';
146			const resolved = new URL(href, `https://ddx.local/${baseDir}`);
147			return {
148				path: decodeURIComponent(resolved.pathname.replace(/^\/+/, '')),
149				hash: resolved.hash ? decodeURIComponent(resolved.hash.slice(1)) : ''
150			};
151		}
152	
153		function slugify(value: string) {
154			return value
155				.toLowerCase()
156				.trim()
157				.replace(/[^\w\s-]/g, '')
158				.replace(/\s+/g, '-');
159		}
160	
161		function scrollToAnchor(anchor: string) {
162			if (!anchor) return;
163			const decoded = decodeURIComponent(anchor);
164			let target = document.getElementById(decoded);
165			if (!target && renderedElement) {
166				target = Array.from(renderedElement.querySelectorAll('h1, h2, h3, h4, h5, h6')).find(
167					(heading) => slugify(heading.textContent ?? '') === decoded
168				) as HTMLElement | null;
169			}
170			target?.scrollIntoView({ behavior: 'smooth', block: 'start' });
171		}
172	
173		function handleRenderedClick(event: MouseEvent) {
174			const target = event.target as Element | null;
175			const anchor = target?.closest?.('a[href]') as HTMLAnchorElement | null;
176			if (!anchor || !renderedElement?.contains(anchor)) return;
177	
178			const href = anchor.getAttribute('href') ?? '';
179			if (!href || isExternalHttpLink(href)) return;
180	
181			if (href.startsWith('#')) {
182				event.preventDefault();
183				scrollToAnchor(href.slice(1));
184				return;
185			}
186	
187			const resolved = resolveDocumentHref(href);
188			if (!resolved.path.endsWith('.md')) return;
189	
190			event.preventDefault();
191			if (resolved.path === data.path && resolved.hash) {
192				scrollToAnchor(resolved.hash);
193				return;
194			}
195	
196			const p = $page.params as Record<string, string>;
197			const hash = resolved.hash ? `#${encodeURIComponent(resolved.hash)}` : '';
198			goto(
199				resolve(
200					`/nodes/${p['nodeId']}/projects/${p['projectId']}/documents/${encodeDocPath(resolved.path)}${hash}`
201				),
202				{ keepFocus: true, noScroll: Boolean(resolved.hash) }
203			).then(() => {
204				if (resolved.hash) scrollToAnchor(resolved.hash);
205			});
206		}
207	
208		function enhanceRenderedLinks() {
209			if (!renderedElement) return;
210			for (const link of renderedElement.querySelectorAll<HTMLAnchorElement>('a[href]')) {
211				const href = link.getAttribute('href') ?? '';
212				if (isExternalHttpLink(href)) {
213					link.target = '_blank';
214					link.rel = 'noopener';
215				}
216			}
217		}
218	
219		function scheduleRenderedLinkEnhancement(html: string) {
220			if (html || html === '') {
221				tick().then(enhanceRenderedLinks);
222			}
223		}
224	
225		$effect(() => {
226			scheduleRenderedLinkEnhancement(rendered);
227		});
228	
229		$effect(() => {
230			const element = renderedElement;
231			if (!element) return;
232			element.addEventListener('click', handleRenderedClick);
233			return () => element.removeEventListener('click', handleRenderedClick);
234		});
235	
236		function handleBack() {
237			const p = $page.params as Record<string, string>;
238			goto(resolve(`/nodes/${p['nodeId']}/projects/${p['projectId']}/documents`));
239		}
240	
241		function startEdit() {
242			editContent = content;
243			editorMode = 'wysiwyg';
244			wysiwygDraftBody = splitMarkdown(content).body;
245			saveError = null;
246			editing = true;
247		}
248	
249		function cancelEdit() {
250			editing = false;
251			saveError = null;
252		}
253	
254		async function handleSave() {
255			commitWysiwygDraft();
256			saving = true;
257			saveError = null;
258			try {
259				const client = createClient();
260				const result = await client.request<DocumentWriteResult>(DOCUMENT_WRITE, {
261					path: data.path,
262					content: editContent
263				});
264				if (result.documentWrite.content != null) {
265					editContent = result.documentWrite.content;
266				}
267				editing = false;
268				await invalidateAll();
269			} catch (e) {
270				saveError = e instanceof Error ? e.message : 'Save failed';
271			} finally {
272				saving = false;
273			}
274		}
275	</script>
276	
277	<div class="space-y-4">
278		<div class="flex items-center gap-3">
279			<button
280				onclick={handleBack}
281				class="flex items-center gap-1.5 rounded-md px-2 py-1.5 text-sm text-gray-600 hover:bg-gray-100 dark:text-gray-400 dark:hover:bg-gray-800"
282			>
283				<ArrowLeft class="h-4 w-4" />
284				Documents
285			</button>
286			<span class="font-mono text-xs text-gray-400 dark:text-gray-600">{data.path}</span>
