63		const client = createClient();
64		const terminalPhases = ['done', 'exited', 'stopped', 'failed', 'error', 'preserved'];
65		const failurePhases = ['failed', 'error'];
66		const subscriptions = new SvelteMap<string, () => void>();
67		const fallbackTimeouts = new SvelteMap<string, number>();
68		const pollingIntervals = new SvelteMap<string, number>();
69	
70		function fallbackDelayMs(): number {
71			if (typeof window === 'undefined') return 30_000;
72			const value = (window as typeof window & { __ddxPluginFallbackDelayMs?: number })
73				.__ddxPluginFallbackDelayMs;
74			return typeof value === 'number' && value >= 0 ? value : 30_000;
75		}
