77		function pollIntervalMs(): number {
78			if (typeof window === 'undefined') return 2_000;
79			const value = (window as typeof window & { __ddxPluginPollIntervalMs?: number })
80				.__ddxPluginPollIntervalMs;
81			return typeof value === 'number' && value > 0 ? value : 2_000;
82		}
