84		function formatDisk(bytes: number): string {
85			const units = ['B', 'KB', 'MB', 'GB'];
86			let value = bytes;
87			let index = 0;
88			while (value >= 1000 && index < units.length - 1) {
89				value /= 1000;
90				index += 1;
91			}
92			const display = value >= 10 || Number.isInteger(value) ? value.toFixed(0) : value.toFixed(1);
93			return `${display} ${units[index]}`;
94		}
