171			const timeout = fallbackTimeouts.get(name);
172			if (timeout != null) window.clearTimeout(timeout);
173			fallbackTimeouts.delete(name);
174	
175			const interval = pollingIntervals.get(name);
176			if (interval != null) window.clearInterval(interval);
177			pollingIntervals.delete(name);
178	
179			inFlightWorkers.delete(name);
