282				}
283	
284				subscribeToWorker(name, workerId, action);
285				scheduleFallbackPolling(name);
286				return true;
287			} catch (err) {
288				dispatchError = err instanceof Error ? err.message : 'Plugin action failed.';
289				return false;
290			} finally {
