11		let executionBySha = $state<Record<string, string | null>>({});
12	
13		onMount(async () => {
14			const client = createClient(fetch);
15			const params = $page.params as Record<string, string>;
16			const projectID = params['projectId'];
17			await Promise.all(
18				data.commits.edges.map(async (edge) => {
19					const sha = edge.node.sha;
20					if (executionBySha[sha] !== undefined) return;
21					try {
22						const result = await client.request<{ executionByResultRev: { id: string } | null }>(
23							COMMIT_EXECUTION_QUERY,
24							{ projectID, sha }
25						);
26						executionBySha = { ...executionBySha, [sha]: result.executionByResultRev?.id ?? null };
27					} catch {
28						executionBySha = { ...executionBySha, [sha]: null };
29					}
30				})
31			);
32		});
