211				}
212			} catch (err) {
213				console.error('[ddx] plugin refresh poll failed:', err);
214			}
215		}
216	
217		function scheduleFallbackPolling(name: string) {
218			const timeout = window.setTimeout(() => {
219				fallbackTimeouts.delete(name);
220				if (inFlightWorkers.has(name)) startFallbackPolling(name);
221			}, fallbackDelayMs());
222			fallbackTimeouts.set(name, timeout);
223		}
224	
225		function subscribeToWorker(name: string, workerId: string, action: PluginAction) {
226			subscriptions.get(name)?.();
