229				(evt) => {
230					if (!isTerminalPhase(evt.phase)) return;
231					void handleWorkerTerminal(name, workerId, action, evt.phase);
232				},
233				(err) => {
234					console.error('[ddx] plugin workerProgress subscription error:', err);
235				}
236			);
237			subscriptions.set(name, dispose);
238		}
239	
240		async function handleWorkerTerminal(
241			name: string,
242			workerId: string,
243			action: PluginAction,
244			phase: string
245		) {
246			if (!inFlightWorkers.has(name)) return;
247			if (isFailurePhase(phase)) {
248				workerFailures.set(name, { workerId, action });
249				clearInFlight(name);
250				return;
251			}
252			try {
253				await refreshPlugins();
254			} catch (err) {
