269			try {
270				const result = await client.request<DispatchResult>(PLUGIN_DISPATCH_MUTATION, {
271					name,
272					action,
273					scope
274				});
275				const workerId = result.pluginDispatch.id;
276				const plugin = pluginByName(name);
277				inFlightWorkers.set(name, workerId);
278				inFlightActions.set(name, action);
279	
280				if (plugin) {
281					dispatchSnapshots.set(name, snapshotFor(plugin));
282				}
283	
284				subscribeToWorker(name, workerId, action);
285				scheduleFallbackPolling(name);
286				return true;
287			} catch (err) {
288				dispatchError = err instanceof Error ? err.message : 'Plugin action failed.';
289				return false;
290			} finally {
291				setDispatching(name, false);
292			}
293		}
294	
295		async function confirmInstall() {
