303		onDestroy(() => {
304			for (const dispose of subscriptions.values()) dispose();
305			for (const timeout of fallbackTimeouts.values()) window.clearTimeout(timeout);
306			for (const interval of pollingIntervals.values()) window.clearInterval(interval);
307		});
