55						requestsLast24h
56					}
57					quota {
58						ceilingTokens
59						ceilingWindowSeconds
60						remaining
61						resetAt
62					}
63					sparkline
64				}
65			}
66		`;
67	
68		const DEFAULT_ROUTE_QUERY = gql`
69			query DefaultRouteStatus {
70				defaultRouteStatus {
71					modelRef
72					resolvedProvider
73					resolvedModel
74					strategy
75				}
76			}
77		`;
78	
79		interface ProviderUsage {
80			tokensUsedLastHour: number | null;
81			tokensUsedLast24h: number | null;
82			requestsLastHour: number | null;
83			requestsLast24h: number | null;
84		}
85	
86		interface ProviderQuota {
87			ceilingTokens: number | null;
88			ceilingWindowSeconds: number | null;
89			remaining: number | null;
90			resetAt: string | null;
91		}
92	
93		interface ProviderStatus {
94			name: string;
95			kind: 'ENDPOINT' | 'HARNESS';
96			providerType: string;
97			baseURL: string;
98			model: string;
99			status: string;
100			reachable: boolean;
101			detail: string;
102			modelCount: number;
103			isDefault: boolean;
104			cooldownUntil: string | null;
105			lastCheckedAt: string | null;
106			defaultForProfile: string[];
107			usage: ProviderUsage | null;
108			quota: ProviderQuota | null;
109			sparkline: number[];
110		}
111	
112		interface DefaultRouteStatus {
113			modelRef: string;
114			resolvedProvider: string | null;
115			resolvedModel: string | null;
116			strategy: string | null;
117		}
118	
119		// First-paint state: we render the table from the query result as soon as
120		// it lands. The query itself returns cached probe results — a live refresh
121		// action will enqueue fresh probes in a future iteration.
122		let rows = $state<ProviderStatus[]>([]);
123		let defaultRoute = $state<DefaultRouteStatus | null>(null);
124		let loading = $state(true);
125		let error = $state<string | null>(null);
126		let firstPaintAt = $state<number | null>(null);
127	
128		$effect(() => {
129			if (!loading && firstPaintAt === null) {
130				firstPaintAt = Date.now();
131			}
132		});
133	
134		// Polling interval for live row patching after first paint. Chosen to be
135		// short enough that probe results surface within the 5s AC budget but long
136		// enough to not hammer the server. AC 1: rows patch within 5s of probe
137		// completion — since the resolver returns cached rows updated asynchronously
138		// by refreshProviderStatuses, polling here is sufficient to reflect them.
139		const POLL_INTERVAL_MS = 2500;
140		let pollTimer: ReturnType<typeof setInterval> | null = null;
141	
142		async function refresh(client: ReturnType<typeof createClient>) {
143			const result = await client.request<{
144				providerStatuses: ProviderStatus[];
145				harnessStatuses: ProviderStatus[];
146			}>(PROVIDER_STATUSES_QUERY);
147			rows = [...(result.providerStatuses ?? []), ...(result.harnessStatuses ?? [])];
148		}
149	
150		onMount(() => {
151			const client = createClient();
152			// First paint: provider + harness rows. defaultRouteStatus fires in
153			// parallel via a separate query so a slow route-resolver can't delay
154			// the table from rendering. AC 1: table interactive within 500ms.
155			refresh(client)
156				.catch((e) => {
157					error = e instanceof Error ? e.message : String(e);
158				})
159				.finally(() => {
160					loading = false;
161				});
162	
163			client
164				.request<{ defaultRouteStatus: DefaultRouteStatus | null }>(DEFAULT_ROUTE_QUERY)
165				.then((res) => {
166					defaultRoute = res.defaultRouteStatus ?? null;
167				})
168				.catch(() => {
169					// Non-fatal: the default-route widget is informational only.
170				});
171	
172			pollTimer = setInterval(() => {
173				refresh(client).catch(() => {
174					// Polling errors are transient; keep the last-known rows.
175				});
176			}, POLL_INTERVAL_MS);
177	
178			return () => {
179				if (pollTimer != null) {
180					clearInterval(pollTimer);
181					pollTimer = null;
182				}
183			};
184		});
185	
186		function statusClass(row: ProviderStatus): string {
187			if (row.reachable) {
188				return 'text-green-600 dark:text-green-400';
189			}
190			const status = row.status;
191			const lower = status.toLowerCase();
192			if (
193				lower.includes('connected') ||
194				lower === 'available' ||
195				lower.includes('api key configured')
196			) {
197				return 'text-green-600 dark:text-green-400';
198			}
199			if (
200				lower.includes('cooldown') ||
201				lower.includes('unreachable') ||
202				lower.includes('error') ||
203				lower === 'unavailable' ||
204				lower.startsWith('unavailable')
205			) {
206				return 'text-red-600 dark:text-red-400';
207			}
208			return 'text-yellow-600 dark:text-yellow-400';
209		}
210	
211		function formatTokens(n: number | null | undefined): string {
212			if (n == null) return '—';
213			if (n < 1000) return `${n}`;
214			if (n < 1_000_000) return `${(n / 1000).toFixed(1)}k`;
215			return `${(n / 1_000_000).toFixed(2)}M`;
216		}
217	
218		function utilizationPct(usage: ProviderUsage | null, quota: ProviderQuota | null): number | null {
219			if (!usage || !quota) return null;
220			if (quota.ceilingTokens == null || quota.ceilingTokens <= 0) return null;
221			const window = quota.ceilingWindowSeconds ?? 60;
222			// Choose the usage field that matches the ceiling window (1h / 24h).
223			const usedTokens = window <= 3600 ? usage.tokensUsedLastHour : usage.tokensUsedLast24h;
224			if (usedTokens == null) return null;
225			return Math.min(100, Math.round((usedTokens * 100) / quota.ceilingTokens));
226		}
227	
228		function sparklineMax(values: number[]): number {
229			let m = 0;
230			for (const v of values) if (v > m) m = v;
231			return m === 0 ? 1 : m;
232		}
233	
234		function sparkBarHeight(value: number, max: number): string {
235			const pct = Math.round((value * 100) / max);
236			return `${Math.max(2, pct)}%`;
237		}
238	
239		function detailHref(row: ProviderStatus): string {
240			const nodeId = $page.params.nodeId;
241			return `/nodes/${nodeId}/providers/${encodeURIComponent(row.name)}`;
242		}
