38		function formatDisk(bytes: number): string {
39			const units = ['B', 'KB', 'MB', 'GB'];
40			let value = bytes;
41			let index = 0;
42			while (value >= 1000 && index < units.length - 1) {
43				value /= 1000;
44				index += 1;
45			}
46			const display = value >= 10 || Number.isInteger(value) ? value.toFixed(0) : value.toFixed(1);
47			return `${display} ${units[index]}`;
48		}
49	
50		function yamlScalar(value: unknown): string {
51			if (typeof value === 'string') return value;
52			if (typeof value === 'number' || typeof value === 'boolean') return String(value);
53			if (value === null) return 'null';
54			return JSON.stringify(value);
55		}
56	
57		function renderYaml(value: unknown, indent = 0): string {
58			const pad = ' '.repeat(indent);
59			if (Array.isArray(value)) {
60				if (value.length === 0) return `${pad}[]`;
61				return value
62					.map((item) =>
63						item && typeof item === 'object'
64							? `${pad}-\n${renderYaml(item, indent + 2)}`
65							: `${pad}- ${yamlScalar(item)}`
66					)
67					.join('\n');
68			}
69			if (value && typeof value === 'object') {
70				const entries = Object.entries(value as Record<string, unknown>);
71				if (entries.length === 0) return `${pad}{}`;
72				return entries
73					.map(([key, item]) =>
74						item && typeof item === 'object'
75							? `${pad}${key}:\n${renderYaml(item, indent + 2)}`
76							: `${pad}${key}: ${yamlScalar(item)}`
77					)
78					.join('\n');
79			}
80			return `${pad}${yamlScalar(value)}`;
81		}
82	
83		function toYaml(value: unknown): string {
84			if (value === null || value === undefined || value === '') return 'manifest: {}';
85			if (typeof value === 'string') {
86				try {
87					return renderYaml(JSON.parse(value));
88				} catch {
89					return value;
90				}
91			}
92			return renderYaml(value);
