45		function splitMarkdown(markdown: string) {
46			const match = markdown.match(/^---\r?\n[\s\S]*?\r?\n---(?:\r?\n|$)/);
47			if (!match) {
48				return { frontmatter: '', frontmatterText: '', body: markdown };
49			}
50			const frontmatter = match[0];
51			const frontmatterText = frontmatter.replace(/^---\r?\n/, '').replace(/\r?\n---(?:\r?\n|$)/, '');
52			return {
53				frontmatter,
54				frontmatterText,
55				body: markdown.slice(frontmatter.length)
56			};
57		}
