86				}
87				if (!(child instanceof HTMLElement)) continue;
88				const tag = child.tagName.toLowerCase();
89				if (/^h[1-6]$/.test(tag)) {
90					addBlock(`${'#'.repeat(Number(tag.slice(1)))} ${textOf(child)}`);
91				} else if (tag === 'ul' || tag === 'ol') {
92					const ordered = tag === 'ol';
93					const items = Array.from(child.querySelectorAll(':scope > li')).map((li, index) => {
94						const marker = ordered ? `${index + 1}.` : '-';
95						return `${marker} ${textOf(li)}`;
